#include<bits/stdc++.h>
using namespace std;
struct edge
{
    long long to,val,nxt,cost;
}e[200010];
long long head[200010],tot=1,res;
long long n,m,s,t,d[200010],now[200010];
bool vis[200010];
void add1(long long u,long long v,long long w,long long c)
{
    e[++tot]=(edge){v,w,head[u],c};
    head[u]=tot;
}
void add(long long u,long long v,long long w,long long c)
{
    add1(u,v,w,c);
    add1(v,u,0,-c);
}
bool spfa()
{
    memset(d,0x3f,sizeof(d));
    long long tmp=d[0];
    queue<long long> q;
    q.push(s);
    d[s]=0;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        vis[t]=false;
        for(int i=head[t];i;i=e[i].nxt)
        {
            int v=e[i].to,cost=e[i].cost;
            if(e[i].val&&d[v]>d[t]+cost)
            {
                d[v]=d[t]+cost;
                if(!vis[v])
                {
                    vis[v]=true;
                    q.push(v);
                }
            }
        }
    }
    return d[t]<tmp;
}
long long dfs(long long x,long long flow)
{
    if(x==t)
    {
        return flow;
    }
    vis[x]=true;
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to,val=e[i].val,cost=e[i].cost;
        if(!vis[v]&&d[v]==d[x]+cost&&val)
        {
            long long tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            res+=tmp*cost;
            flow-=tmp;
        }
    }
    vis[x]=false;
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(spfa())
    {
        for(long long i=0;i<=t;i++)
        {
            now[i]=head[i];
        }
        ans+=dfs(s,INT_MAX);
    }
    return ans;
}
long long a[110],b[110],c[110][110];
int main()
{
    scanf("%lld%lld",&n,&m);
    s=n+m+1;
    t=s+1;
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        add(s,i,a[i],0);
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld",&b[i]);
        add(i+n,t,b[i],0);
    }
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m;j++)
        {
            scanf("%lld",&c[i][j]);
            add(i,j+n,2e9,c[i][j]);
        }
    }
    dinic();
    long long ans=res;
    res=0;
    memset(head,0,sizeof(head));
    memset(e,0,sizeof(e));
    memset(vis,0,sizeof(vis));
    tot=1;
    for(long long i=1;i<=n;i++)
    {
        add(s,i,a[i],0);
    }
    for(long long i=1;i<=m;i++)
    {
        add(i+n,t,b[i],0);
    }
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m;j++)
        {
            add(i,j+n,2e9,-c[i][j]);
        }
    }
    dinic();
    printf("%lld\n%lld",ans,-res);
    return 0;
}
